consumer_query_patterns:
// All unused declared dependencies in a specific module
MATCH (m:Module {name: $module_name})-[d:DECLARES_DEP {is_used: false}]->(dep:Dependency)
RETURN dep.artifact_id, dep.version, d.config ORDER BY dep.artifact_id

// Transitive-leak deps (used in code but only transitively declared)
MATCH (m:Module)-[d:DECLARES_DEP {is_transitive_leak: true}]->(dep:Dependency)
RETURN m.name, dep.artifact_id, dep.version, d.recommendation

// All modules depending on a specific library version
MATCH (m:Module)-[:DECLARES_DEP]->(dep:Dependency {artifact_id: 'retrofit', version: '2.9.0'})
RETURN m.name, m.build_system

// DepFindings by type across all modules
MATCH (f:DepFinding)
RETURN f.finding_type, count(f) AS count, collect(f.module)[..5] AS sample_modules ORDER BY count DESC
